export class Disposable{dispose(){}}export class EventEmitter{constructor(){this._listeners=[]}fire(e){this._listeners.forEach(l=>l(e))}dispose(){this._listeners=[]}}
export class Uri{static parse(u){return new Uri(u)}static file(p){return new Uri(p)}constructor(u){this.scheme=u.includes('://')?u.split('://')[0]:'file';this.path=u.includes('://')?u.split('://')[1]:u}toString(){return this.scheme+'://'+this.path}toJSON(){return this}}
